async function notifyPaymentService(orderId: string, amount: number, currency: string = 'EUR') {
    const response = await fetch(`${process.env.PAYMENT_SERVICE_URL}/api/payments`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
            orderId,
            amount,
